// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getOverview,
  getUsers,
  getRiders,
  getApprovedCaptains,
  getPendingCaptains,
  approveCaptain,
  rejectCaptain,
} from "../../services/adminApi";
import {
  Paper,
  Typography,
  Grid,
  Card,
  CardContent,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  Button,
  Tabs,
  Tab,
  IconButton,
} from "@mui/material";
import PeopleIcon from "@mui/icons-material/People";
import DirectionsCarIcon from "@mui/icons-material/DirectionsCar";
import PendingActionsIcon from "@mui/icons-material/PendingActions";
import CheckCircleIcon from "@mui/icons-material/CheckCircle";
import AssignmentIcon from "@mui/icons-material/Assignment";
import DownloadIcon from "@mui/icons-material/Download";

export default function AdminDashboard() {
  const [overview, setOverview] = useState({});
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState(0);
  const [users, setUsers] = useState([]);
  const [riders, setRiders] = useState([]);
  const [approvedCaptains, setApprovedCaptains] = useState([]);
  const [pendingCaptains, setPendingCaptains] = useState([]);

  const fetchOverview = async () => {
    try {
      const res = await getOverview();
      setOverview(res.data);
    } catch (err) {
      console.error("Overview fetch error:", err);
    }
  };

  const fetchData = async () => {
    try {
      const [usersRes, ridersRes, approvedRes, pendingRes] = await Promise.all([
        getUsers(),
        getRiders(),
        getApprovedCaptains(),
        getPendingCaptains(),
      ]);
      setUsers(usersRes.data.users);
      setRiders(ridersRes.data.riders);
      setApprovedCaptains(approvedRes.data.captains);
      setPendingCaptains(pendingRes.data.pendingCaptains);
    } catch (err) {
      console.error("Data fetch error:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchOverview();
    fetchData();
  }, []);

  const handleApprove = async (id) => {
    try {
      await approveCaptain(id);
      fetchOverview();
      fetchData();
    } catch (err) {
      console.error("Approve error:", err);
    }
  };

  const handleReject = async (id) => {
    try {
      await rejectCaptain(id);
      fetchOverview();
      fetchData();
    } catch (err) {
      console.error("Reject error:", err);
    }
  };

  const handleTabChange = (event, newValue) => setTab(newValue);

  const renderTable = (data, isPending = false) => (
    <Table>
      <TableHead>
        <TableRow>
          <TableCell>Name</TableCell>
          <TableCell>Email</TableCell>
          <TableCell>Mobile</TableCell>
          <TableCell>Role</TableCell>
          <TableCell>Login Count</TableCell>
          <TableCell>Approval Status</TableCell>
          <TableCell>Documents</TableCell>
          {isPending && <TableCell>Actions</TableCell>}
        </TableRow>
      </TableHead>
      <TableBody>
        {data.length === 0 ? (
          <TableRow>
            <TableCell colSpan={isPending ? 8 : 7} align="center">
              No data found
            </TableCell>
          </TableRow>
        ) : (
          data.map((item) => (
            <TableRow key={item._id}>
              <TableCell>{item.fullName}</TableCell>
              <TableCell>{item.email}</TableCell>
              <TableCell>{item.mobile}</TableCell>
              <TableCell>{item.role}</TableCell>
              <TableCell>{item.loginCount}</TableCell>
              <TableCell>{item.approvalStatus}</TableCell>
              <TableCell>
                {item.documents.length === 0
                  ? "-"
                  : item.documents.map((doc, i) => (
                      <div key={i}>
                        <a href={doc.path} target="_blank" rel="noreferrer">
                          {doc.filename} <IconButton><DownloadIcon /></IconButton>
                        </a>
                      </div>
                    ))}
              </TableCell>
              {isPending && (
                <TableCell>
                  <Button
                    color="success"
                    variant="contained"
                    size="small"
                    onClick={() => handleApprove(item._id)}
                    sx={{ mr: 1 }}
                  >
                    Approve
                  </Button>
                  <Button
                    color="error"
                    variant="contained"
                    size="small"
                    onClick={() => handleReject(item._id)}
                  >
                    Reject
                  </Button>
                </TableCell>
              )}
            </TableRow>
          ))
        )}
      </TableBody>
    </Table>
  );

  if (loading) return <Typography>Loading...</Typography>;

  return (
    <div>
      <Typography variant="h4" gutterBottom>
        Admin Dashboard
      </Typography>

      {/* Overview Cards */}
      <Grid container spacing={2} sx={{ mb: 3 }}>
        <Grid item xs={12} sm={6} md={2}>
          <Card>
            <CardContent>
              <PeopleIcon fontSize="large" color="primary" />
              <Typography variant="h6">Users</Typography>
              <Typography variant="h5">{overview.users || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card>
            <CardContent>
              <DirectionsCarIcon fontSize="large" color="secondary" />
              <Typography variant="h6">Riders</Typography>
              <Typography variant="h5">{overview.riders || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card>
            <CardContent>
              <CheckCircleIcon fontSize="large" color="success" />
              <Typography variant="h6">Approved Captains</Typography>
              <Typography variant="h5">{overview.captains || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card>
            <CardContent>
              <PendingActionsIcon fontSize="large" color="warning" />
              <Typography variant="h6">Pending Captains</Typography>
              <Typography variant="h5">{overview.pendingCaptains || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
        <Grid item xs={12} sm={6} md={2}>
          <Card>
            <CardContent>
              <AssignmentIcon fontSize="large" color="info" />
              <Typography variant="h6">Total Rides</Typography>
              <Typography variant="h5">{overview.rides || 0}</Typography>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      {/* Tabs */}
      <Tabs value={tab} onChange={handleTabChange} sx={{ mb: 2 }}>
        <Tab label="Users" />
        <Tab label="Riders" />
        <Tab label="Approved Captains" />
        <Tab label="Pending Captains" />
      </Tabs>

      <Paper sx={{ p: 2 }}>
        {tab === 0 && renderTable(users)}
        {tab === 1 && renderTable(riders)}
        {tab === 2 && renderTable(approvedCaptains)}
        {tab === 3 && renderTable(pendingCaptains, true)}
      </Paper>
    </div>
  );
}
